class Solution:
    def commonFactors(self, a, b):
        from math import gcd
        g = gcd(a, b)
        count = 0
        d = 1
        while d * d <= g:
            if g % d == 0:
                count += 1
                if d != g // d:
                    count += 1
            d += 1
        return count

