var commonFactors = function(a, b) {
    const gcd = (x, y) => { while (y) { [x, y] = [y, x % y]; } return x; };
    const g = gcd(a, b);
    let count = 0;
    for (let d = 1; d * d <= g; d++) {
        if (g % d === 0) {
            count++;
            if (d !== g / d) count++;
        }
    }
    return count;
};
